1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. public class ModelTrainingService
8. {
9.     private readonly string _dataPath;
10.     private readonly string _modelPath;
11.     private readonly ILogger<ModelTrainingService> _logger;
12. 
13.     public ModelTrainingService(ILogger<ModelTrainingService> logger)
14.     {
15.         _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
16.         _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
17.         _logger = logger;
18.     }
19. 
20.     public string ModelPath => _modelPath;
21. 
22.     /// <summary>Label names in the order ML.NET assigned key values (score array order).</summary>
23.     public string[] LabelNames { get; private set; } = [];
24. 
25.     public void TrainAndEvaluate()
26.     {
27.         var mlContext = new MLContext(seed: 42);
28. 
29.         // Load data
30.         var data = mlContext.Data.LoadFromTextFile<TicketInput>(
31.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
32. 
33.         // Split data for evaluation
34.         var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
35. 
36.         // Build pipeline: featurize text + numeric, then classify
37.         var pipeline = mlContext.Transforms.Conversion
38.             .MapValueToKey("Label", nameof(TicketInput.Category))
39.             .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
40.             .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
41.             .Append(mlContext.Transforms.Concatenate("Features",
42.                 "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
43.             .Append(mlContext.Transforms.NormalizeMinMax("Features"))
44.             .Append(mlContext.MulticlassClassification.Trainers
45.                 .SdcaMaximumEntropy("Label", "Features"))
46.             .Append(mlContext.Transforms.Conversion
47.                 .MapKeyToValue("PredictedLabel"));
48. 
49.         // Train
50.         _logger.LogInformation("Training model on {Path}...", _dataPath);
51.         var model = pipeline.Fit(split.TrainSet);
52. 
53.         // Extract label ordering from the trained model's Score column metadata
54.         var scoreMeta = model.GetOutputSchema(data.Schema)["Score"];
55.         var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
56.         scoreMeta.GetSlotNames(ref labelBuffer);
57.         LabelNames = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
58.         _logger.LogInformation("Label order: {Labels}", string.Join(", ", LabelNames));
59. 
60.         // Evaluate on test set
61.         var predictions = model.Transform(split.TestSet);
62.         var metrics = mlContext.MulticlassClassification.Evaluate(predictions);
63. 
64.         _logger.LogInformation("=== Model Evaluation Metrics ===");
65.         _logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
66.         _logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
67.         _logger.LogInformation("  Log Loss:          {LogLoss:F4}", metrics.LogLoss);
68.         _logger.LogInformation("  Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);
69. 
70.         // Log per-class metrics
71.         for (int i = 0; i < LabelNames.Length; i++)
72.         {
73.             _logger.LogInformation("  [{Label}] Log-loss: {Loss:F4}",
74.                 LabelNames[i],
75.                 i < metrics.PerClassLogLoss.Count ? metrics.PerClassLogLoss[i] : double.NaN);
76.         }
77. 
78.         // Save model
79.         mlContext.Model.Save(model, data.Schema, _modelPath);
80.         _logger.LogInformation("Model saved to {ModelPath}", _modelPath);
81.     }
82. }
83.

